def segment_by_impact(
    accounts: list[AffectedAccount],
    severity: str,
) -> dict[str, list[AffectedAccount]]:
    """Segment accounts for targeted communication."""
    return {
        "enterprise_high_volume": [
            a for a in accounts
            if a.is_enterprise and a.session_count_during_incident > 100
        ],
        "enterprise_low_volume": [
            a for a in accounts
            if a.is_enterprise and a.session_count_during_incident <= 100
        ],
        "standard_affected": [
            a for a in accounts
            if not a.is_enterprise and a.session_count_during_incident > 0
        ],
    }


def send_notification(
    account: AffectedAccount,
    template_body: str,
    subject: str,
    sendgrid_api_key: str,
) -> bool:
    """Send a templated notification via SendGrid."""
    with httpx.Client() as client:
        resp = client.post(
            "https://api.sendgrid.com/v3/mail/send",
            headers={
                "Authorization": f"Bearer {sendgrid_api_key}",
                "Content-Type": "application/json",
            },
            json={
                "personalizations": [{
                    "to": [{"email": account.contact_email, "name": account.account_name}],
                    "dynamic_template_data": {
                        "account_name": account.account_name,
                        "incident_details": account.impact_description,
                    }
                }],
                "from": {"email": "noreply@yourcompany.com", "name": "YourCompany Support"},
                "subject": subject,
                "content": [{"type": "text/html", "value": template_body}],
            },
            timeout=10,
        )
        return resp.status_code == 202


def run_notification_campaign(
    incident_start: datetime,
    incident_end: datetime,
    incident_category: str,
    severity: str,
    email_template: str,
    subject: str,
    dry_run: bool = True,
) -> dict:
    """Run the full notification campaign for an incident."""
    accounts = identify_affected_accounts(incident_start, incident_end, incident_category)
    segments = segment_by_impact(accounts, severity)

    sent, failed = 0, 0
    for segment_name, segment_accounts in segments.items():
        for account in segment_accounts:
            if not dry_run:
                success = send_notification(
                    account, email_template, subject,
                    os.environ["SENDGRID_API_KEY"]
                )
                if success:
                    sent += 1
                else:
                    failed += 1
            else:
                print(f"[DRY RUN] Would notify {account.account_name} ({segment_name})")

    return {"sent": sent, "failed": failed, "dry_run": dry_run}
